export const PIVOT_LEVELS = PV_DATA.map((d, i) => ({ id: i + 1, name: PV_META[i].name, hint: PV_META[i].hint, ...d }));
export const TOTAL_LEVELS = PIVOT_LEVELS.length;

// ── Daily challenge — deterministic by date, validated at runtime ─────
// ── Daily challenge — deterministic by date, validated at runtime ─────
function pvSeededRandom(seed) {
  let s = seed % 2147483647; if (s <= 0) s += 2147483646;
  return () => (s = (s * 16807) % 2147483647) / 2147483647;
}
function pvDateSeed(d = new Date()) {
  return d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate();
}
function pvBuildDaily(seed) {
  const rnd = pvSeededRandom(seed);
  const pick = (a, b) => a + rnd() * (b - a);
  const nT = 3 + Math.floor(rnd() * 2);
  const ball = { x: Math.round(pick(60, 260)), y: 422 };
  const targets = [];
  for (let i = 0; i < nT; i++) {
    let tries = 0, t;
    do { t = { x: Math.round(pick(48, 272)), y: Math.round(pick(85, 295)) }; tries++; }
    while (tries < 30 && (Math.hypot(t.x - ball.x, t.y - ball.y) < 70 || targets.some(o => Math.hypot(o.x - t.x, o.y - t.y) < 72)));
    targets.push(t);
  }
  const walls = [];
  const nW = 2 + Math.floor(rnd() * 2);
  for (let i = 0; i < nW; i++) {
    if (rnd() > 0.5) { const x = Math.round(pick(90, 230)); const y0 = Math.round(pick(180, 250)); walls.push({ x1: x, y1: y0, x2: x, y2: y0 + Math.round(pick(80, 130)) }); }
    else { const y = Math.round(pick(210, 330)); const x0 = Math.round(pick(45, 120)); walls.push({ x1: x0, y1: y, x2: x0 + Math.round(pick(110, 165)), y2: y }); }
  }
  return { ball, targets, walls, speed: 540 };
}
// count winning angles using the live engine (available at app runtime)
function pvBandCount(L) {
  if (typeof pvStep !== "function") return 99;
  const P = { g: 300, airDrag: 0.05, eEdge: 0.9, eWall: 0.88, ft: 0.985 };
  let wins = 0;
  for (let a = 12; a <= 172; a += 8) {
    const b = { x: L.ball.x, y: L.ball.y };
    const r = a * Math.PI / 180; b.vx = Math.cos(r) * L.speed; b.vy = -Math.sin(r) * L.speed;
    const tg = L.targets.map(t => ({ ...t, hit: false }));
    let rest = 0, ok = false;
    for (let s = 0; s < 560; s++) {
      pvStep(b, tg, L.walls, PV_BOARD, P, 1 / 60);
      if (tg.every(t => t.hit)) { ok = true; break; }
      const sp = Math.hypot(b.vx, b.vy);
      if (sp < 16) rest += 1 / 60; else rest = 0;
      if (rest > 0.9) break;
    }
    if (ok) { wins++; if (wins >= 2) return wins; }
  }
  return wins;
}
function pvGenerateDaily(seed) {
  for (let k = 0; k < 60; k++) {
    const L = pvBuildDaily(seed + k * 7919);
    if (pvBandCount(L) >= 2) {
      return { id: "daily-" + seed, name: "Daily Challenge", daily: true,
        par: L.targets.length, hint: "One run on the board. Resets at midnight.", ...L };
    }
  }
  const L = pvBuildDaily(seed);
  return { id: "daily-" + seed, name: "Daily Challenge", daily: true, par: L.targets.length, hint: "One run on the board.", ...L };
}

export { pvGenerateDaily, pvDateSeed, pvSeededRandom };
